// src/resolver/variable-resolver.ts
function resolveVariables(input, variables) {
  let result = input;
  result = result.replace(/\\\{/g, "\0ESCAPE_OPEN\0");
  result = result.replace(/\\\}/g, "\0ESCAPE_CLOSE\0");
  result = result.replace(/\{\{([^}]+)\}\}/g, (_, varName) => {
    const trimmed = varName.trim();
    if (variables.hasOwnProperty(trimmed)) {
      return variables[trimmed];
    }
    return `{{${trimmed}}}`;
  });
  result = result.replace(/\x00ESCAPE_OPEN\x00/g, "{");
  result = result.replace(/\x00ESCAPE_CLOSE\x00/g, "}");
  return result;
}
function resolveDsn(dsnTemplate, variables) {
  return resolveVariables(dsnTemplate, variables);
}
function resolveQuery(query, variables) {
  return resolveVariables(query, variables);
}

// src/processor/comment-processor.ts
async function processCustomComments2(entry, variables) {
  const results = [];
  if (!entry.customComments || entry.customComments.length === 0) {
    return { success: true, results };
  }
  let order = 1;
  for (const comment of entry.customComments) {
    try {
      const dsn = resolveDsn(comment.dsnVariable, variables);
      const query = resolveQuery(comment.query, variables);
      const connector = createConnector(comment.dbType);
      await connector.connect();
      let queryResult;
      if (comment.dbType === "mongodb") {
        const mongodbConnector = connector;
        if (mongodbConnector.executeCommand) {
          queryResult = await mongodbConnector.executeCommand(JSON.parse(query));
        } else {
          throw new Error("MongoDB connector does not support executeCommand");
        }
      } else {
        queryResult = await connector.query(query);
      }
      await connector.disconnect();
      results.push({
        order: order++,
        type: comment.dbType,
        action: comment.action,
        query,
        result: queryResult
      });
    } catch (error) {
      return {
        success: false,
        results,
        error: `Failed to process ${comment.dbType} query: ${error}`
      };
    }
  }
  return { success: true, results };
}
function getScreenshotActions(results) {
  return results.filter(
    (r) => r.action === "screenshot" || r.action === "pre-output" || r.action === "post-output"
  );
}

// src/handler/skip-handler.ts
function shouldSkipOutput(entry) {
  return entry.skip === true;
}
function getSkippedEntries(entries) {
  return entries.filter((e) => e.skip).map((e) => e.index);
}

