async function run() {
  const program2 = new Command();
  program2.name("smoke-test-maker").description("CLI tool to generate smoke tests from .hurl files with DB query integration").version("1.0.0").argument("<input>", "Path to .hurl file").option("-e, --env <path>", "Path to .env file").option("-o, --output-dir <path>", "Output directory").option("-s, --stop-on-failure", "Stop execution on first failure", false).option("--strict", "Exit with error if any case fails", false).option("-v, --variable <key=value>", "Set variable (can be repeated)", (val, prev) => {
    if (!prev) prev = [];
    prev.push(val);
    return prev;
  }, []);
  program2.parse(process.argv);
  const inputFile = program2.args[0];
  const opts = program2.opts();
  if (!inputFile) {
    program2.error("Input file is required");
  }
  const variables = {};
  if (opts.variable) {
    for (const v of opts.variable) {
      const [key, ...valueParts] = v.split("=");
      if (key && valueParts.length > 0) {
        variables[key] = valueParts.join("=");
      }
    }
  }
  let envPath = null;
  if (opts.env) {
    envPath = (0, import_path3.resolve)(process.cwd(), opts.env);
  } else {
    const autoEnvPath = (0, import_path3.join)((0, import_path3.dirname)(inputFile), ".env");
    if ((0, import_fs5.existsSync)(autoEnvPath)) {
      envPath = autoEnvPath;
    }
  }
  if (envPath) {
    try {
      const envConfig = (0, import_dotenv.parse)((0, import_fs4.readFileSync)(envPath));
      for (const [key, value] of Object.entries(envConfig)) {
        variables[key] = value;
      }
      console.log("Loaded .env from:", envPath);
    } catch (err) {
      console.warn(`Warning: Could not load .env file: ${err}`);
    }
  }
  const defaultOutputDir = (0, import_path3.join)((0, import_path3.dirname)(inputFile), "output");
  const options = {
    inputFile,
    envFile: opts.env,
    outputDir: opts.outputDir ?? defaultOutputDir,
    stopOnFailure: opts.stopOnFailure ?? false,
    strict: opts.strict ?? false,
    variables
  };
  const startTime = Date.now();
  let success = true;
  let error;
  try {
    console.log("Parsing hurl file:", options.inputFile);
    const hurlFile = parseHurlFile(options.inputFile);
    console.log(`Found ${hurlFile.entries.length} entries`);
    console.log("Executing entries...");
    const execOptions = {
      stopOnFailure: options.stopOnFailure,
      outputDir: options.outputDir,
      variables: options.variables,
      inputFile,
      strict: options.strict
    };
    const results = await executeHurlFile(hurlFile, execOptions);
    console.log(`Executed ${results.length} entries`);
    const outputs = [];
    const skippedEntries = getSkippedEntries(hurlFile.entries);
    const accumulatedData = [];
    let entryData = null;
    console.log("Processing outputs...");
    for (const result of results) {
      const entry = hurlFile.entries.find((e) => e.index === result.index);
      if (!entry) continue;
      const databases = [];
      const mergedVariables = { ...options.variables, ...result.capturedVars };
      if (entry.customComments && entry.customComments.length > 0) {
        const dbResult = await processCustomComments2(entry, mergedVariables);
        if (!dbResult.success) {
          console.error(`DB query failed for entry ${entry.index}: ${dbResult.error}`);
          databases.push(...dbResult.results);
        } else {
          databases.push(...dbResult.results);
        }
      }
      entryData = {
        httpResponse: result.response ? {
          ...result.response,
          headers: filterHeaders(result.response.headers || {}, entry.showHeaders)
        } : null,
        databases,
        requestBody: entry.request?.body,
        requestUrl: entry.request?.url,
        requestMethod: entry.request?.method
      };
      accumulatedData.push(entryData);
      const screenshotActions = getScreenshotActions(databases);
      if (screenshotActions.length > 0) {
        const caseName = `case${entry.index}_screenshot_${screenshotActions.filter((a) => a.action === "screenshot" || a.action === "pre-output" || a.action === "post-output").length}`;
        const html = generateHtml([entryData]);
        const pngPath = await htmlToPng(html, { outputDir: options.outputDir, caseName });
        console.log(`Generated screenshot: ${pngPath}`);
      }
      if (!shouldSkipOutput(entry)) {
        const caseName = `case${entry.index}`;
        const output = generateOutput(
          entry.index,
          result.success,
          result.response,
          databases,
          { outputDir: options.outputDir, caseName, showHeaders: entry.showHeaders }
        );
        const filepath = await writeOutputFile(output, { outputDir: options.outputDir });
        console.log(`Wrote output: ${filepath}`);
        outputs.push(output);
      }
    }
    const totalDuration = Date.now() - startTime;
    console.log("\n--- Summary ---");
    console.log(`Total entries: ${results.length}`);
    console.log(`Successful: ${results.filter((r) => r.success).length}`);
    console.log(`Failed: ${results.filter((r) => !r.success).length}`);
    console.log(`Skipped: ${skippedEntries.length}`);
    console.log(`Output files: ${outputs.length}`);
    console.log(`Duration: ${totalDuration}ms`);
    const hasFailures = results.some((r) => !r.success);
    if (options.strict && hasFailures) {
      const failedResults = results.filter((r) => !r.success);
      for (const r of failedResults) {
        if (r.error) {
          console.error(`
=== Entry ${r.index} Error ===`);
          console.error(r.error);
        }
      }
      process.exit(1);
    }
    if (hasFailures) {
      console.error("\n=== Failed Entries ===");
      for (const r of results) {
        if (!r.success) {
          console.error(`
Entry ${r.index} FAILED:`);
          if (r.error) {
            const errLines = r.error.split("\n").slice(-10);
            for (const line of errLines) {
              console.error("  " + line);
            }
          }
        }
      }
      success = false;
    }
  } catch (err) {
    error = String(err);
    console.error("Error:", error);
    success = false;
  }
  const exitCode = success ? 0 : 1;
  process.exit(exitCode);
}
